def filter_by_quantile(loss_tensor, valid_range, min_elements=1000, hard_max=100.0):
    if loss_tensor.numel() <= min_elements:
        return loss_tensor

    loss_val = loss_tensor.detach().clamp(max=hard_max)

    if loss_val.numel() > 10_000_000:
        perm = torch.randperm(loss_val.numel(), device=loss_val.device)[:1_000_000]
        loss_val = loss_val.view(-1)[perm]

    k = ceil(valid_range * (loss_val.numel() - 1)) + 1
    quantile_thresh = torch.kthvalue(loss_val.view(-1), k)[0]
    quantile_thresh = min(quantile_thresh.item(), hard_max)

    mask = loss_tensor <= quantile_thresh
    if mask.sum() < min_elements:
        return loss_tensor.clamp(max=hard_max)
        
    return loss_tensor[mask]

